import type { GlosarioItem } from '../../types';

/* ─── GLOSARIO: científico ─── */
export const GLOSARIO_CIENTIFICO: GlosarioItem[] = [
  // ─── Inoculantes y Consorcios ───
  { termino: 'Inoculantes Microbianos', definicion: 'Productos biológicos que contienen microorganismos vivos seleccionados y formulados para ser aplicados a semillas, plantas o suelo con la finalidad de establecer poblaciones benéficas que mejoren el crecimiento vegetal, la disponibilidad de nutrientes y la salud del ecosistema agrícola. Su principio fundamental consiste en introducir microorganismos funcionales capaces de colonizar la rizósfera, asociarse con raíces, formar simbiosis, producir metabolitos beneficiosos, modificar la disponibilidad de nutrientes y competir con organismos perjudiciales. Los tipos principales incluyen: inoculantes fijadores de nitrógeno (Rhizobium, Bradyrhizobium en simbiosis con leguminosas; Azospirillum, Azotobacter como bacterias asociativas que además producen auxinas y estimulan el desarrollo radicular), inoculantes micorrícicos (hongos micorrícicos arbusculares HMA como Rhizophagus, Funneliformis, Claroideoglomus que forman simbiosis con la mayoría de plantas terrestres, ampliando el volumen de suelo explorado, mejorando absorción de fósforo y agua, produciendo glomalina que estabiliza agregados y protegiendo frente a estrés hídrico y salinidad), inoculantes solubilizadores de fósforo (Bacillus, Pseudomonas, Aspergillus, Penicillium que liberan ácidos orgánicos, fosfatasas y quelantes naturales que movilizan fósforo inmovilizado en minerales), inoculantes movilizadores de potasio (Bacillus mucilaginosus, Frateuria aurantia que liberan potasio atrapado en minerales mediante ácidos orgánicos y alteración mineral), bacterias promotoras del crecimiento vegetal PGPR (Bacillus, Pseudomonas, Azospirillum, Enterobacter, Paenibacillus que producen auxinas, sideróforos, solubilizan nutrientes, reducen estrés vegetal y compiten contra patógenos), inoculantes antagonistas de patógenos (Trichoderma spp. contra Fusarium, Rhizoctonia, Pythium mediante competencia, antibiosis, enzimas líticas e inducción de resistencia; Bacillus spp. que producen compuestos antimicrobianos naturales) y consorcios microbianos (mezclas de microorganismos compatibles como Azospirillum para crecimiento radicular + Bacillus para protección y solubilización + micorrizas para absorción mineral + Trichoderma para defensa, generando efectos superiores a una sola especie). Los métodos de aplicación incluyen inoculación de semillas (contacto temprano, colonización inicial, bajo costo), inmersión radicular (trasplantes, viveros), aplicación al suelo (introducción directa en la rizósfera), fertirrigación (cultivos intensivos) y aplicación foliar (microorganismos epífitos). Para que un inoculante funcione debe superar supervivencia (resistir temperatura, humedad y competencia microbiana), adhesión (a semillas, raíces o partículas del suelo), multiplicación y establecimiento, e interacción con la planta. Las formulaciones pueden ser líquidas (fácil aplicación, rápida activación), sólidas (turba, compost, minerales portadores) o microencapsuladas (matrices biodegradables que protegen al microorganismo y permiten liberación gradual con mayor vida útil). La eficiencia depende de compatibilidad microorganismo-planta, tipo de suelo, pH, temperatura, humedad, materia orgánica y presencia de agroquímicos. El control de calidad incluye identificación genética del microorganismo, concentración celular, viabilidad, pureza, estabilidad y eficacia agronómica. Los inoculantes no reemplazan la biodiversidad natural sino que buscan complementar y estimular procesos existentes, integrando conocimiento de microbiología, genética y ecología para restaurar relaciones biológicas fundamentales entre plantas y microorganismos, transformando suelos degradados en ecosistemas agrícolas más vivos, eficientes y resilientes.' },
  { termino: 'Consorcios Microbianos', definicion: 'Comunidades organizadas de dos o más microorganismos compatibles que interactúan entre sí y realizan funciones complementarias para mejorar procesos biológicos específicos en el agroecosistema, como nutrición vegetal, protección contra patógenos, descomposición de materia orgánica, formación de humus y restauración de la fertilidad del suelo. A diferencia de un inoculante monoespecífico, un consorcio microbiano incorpora diferentes organismos con funciones complementarias generando una red biológica capaz de adaptarse mejor a condiciones ambientales variables, combinando cooperación metabólica, intercambio de nutrientes y mayor estabilidad ecológica. Los principios ecológicos que rigen los consorcios incluyen: cooperación microbiana (intercambio de metabolitos, producción de factores de crecimiento y modificación del ambiente), complementariedad funcional (cada microorganismo aporta una función diferente: fijación de nitrógeno, solubilización de fósforo, protección biológica, descomposición de lignina y celulosa) y redes metabólicas (los productos metabólicos de un microorganismo se convierten en recursos para otro). Los tipos principales de consorcios agrícolas son: consorcios promotores del crecimiento vegetal (PGPR, micorrizas, bacterias fijadoras de nitrógeno que estimulan desarrollo radicular, mejoran nutrición y aumentan resistencia), consorcios descomponedores (hongos celulolíticos, bacterias degradadoras, actinobacterias que forman humus, liberan nutrientes y aumentan carbono orgánico), consorcios de control biológico (Trichoderma spp., Bacillus spp., Pseudomonas spp. que actúan mediante competencia, antibiosis, parasitismo e inducción de resistencia) y consorcios para recuperación de suelos degradados (microorganismos capaces de degradar contaminantes, recuperar estructura, aumentar materia orgánica y estimular raíces pioneras). Los microorganismos fundamentales en consorcios agrícolas incluyen bacterias fijadoras de nitrógeno (Rhizobium, Azospirillum, Azotobacter), bacterias solubilizadoras de fósforo (Bacillus, Pseudomonas), hongos micorrícicos arbusculares (exploración del suelo, transporte de nutrientes, formación de redes subterráneas), Trichoderma (antagonismo, estimulación radicular, producción de enzimas), levaduras (vitaminas, metabolitos, estimulación microbiana) y actinobacterias como Streptomyces (degradación de materia orgánica, antibióticos naturales, formación de suelo estable). La tecnología de producción de consorcios incluye fermentación líquida, fermentación sólida y cultivo mixto en biofábricas, donde la tendencia actual es pasar de producir microorganismos individuales hacia fabricar comunidades microbianas diseñadas que imiten la organización natural de los ecosistemas, donde cada integrante cumple una función dentro de una red biológica cooperativa.' },
  // ─── Ingeniería Genética y Edición Génica ───
  { termino: 'Ingeniería Genética Agrícola', definicion: 'Rama de la biotecnología que utiliza técnicas de biología molecular para modificar directamente el material genético de plantas, microorganismos u otros organismos con el objetivo de introducir, eliminar o alterar características específicas de interés agrícola, fundamentada en la manipulación del ADN que contiene la información hereditaria para dirigir la formación y funcionamiento de los organismos vivos. A diferencia del mejoramiento tradicional que cruza organismos completos y selecciona durante muchas generaciones, la ingeniería genética permite identificar genes específicos, transferir fragmentos de ADN, modificar rutas metabólicas y activar o silenciar genes con mayor precisión y rapidez. Las herramientas principales incluyen: ADN recombinante (técnica que combina fragmentos de ADN de diferentes organismos mediante selección del gen, corte del ADN con enzimas de restricción, inserción en un vector y expresión en el organismo receptor), vectores genéticos (plásmidos bacterianos, virus modificados, cromosomas artificiales utilizados como vehículos para transportar genes), transformación genética vegetal mediante Agrobacterium tumefaciens (bacteria capaz de transferir ADN a células vegetales de forma natural) y biobalística (partículas microscópicas recubiertas de ADN introducidas en células mediante presión), y edición génica (CRISPR/Cas9, TALEN, ZFN que permiten modificar genes existentes con precisión milimétrica). Las aplicaciones principales incluyen: resistencia a insectos mediante genes de Bacillus thuringiensis (Bt) que producen proteínas Cry tóxicas específicas para ciertos insectos sin afectar otros organismos, tolerancia a herbicidas que permite controlar malezas sin afectar el cultivo, resistencia a enfermedades mediante genes de reconocimiento de patógenos y producción de defensas, tolerancia a estrés climático (sequía, salinidad, temperaturas extremas) mediante genes de regulación hídrica, antioxidantes y proteínas protectoras, mejora del uso de nutrientes (plantas que captan mejor fósforo, utilizan nitrógeno eficientemente y se asocian mejor con microorganismos), mejora nutricional (modificación de vitaminas, aceites, proteínas y aminoácidos), y producción de moléculas útiles como vacunas, enzimas y compuestos farmacéuticos. En microorganismos agrícolas, la ingeniería genética permite diseñar bacterias para producir fitohormonas, enzimas degradadoras, compuestos antimicrobianos y metabolitos específicos para biofertilizantes, biopesticidas y bioestimulantes mejorados. La ingeniería genética debe entenderse como una herramienta dentro de un sistema biológico más amplio donde plantas, microorganismos y ambiente interactúan permanentemente, requiriendo evaluación rigurosa de impacto ecológico, flujo génico, efectos sobre organismos no objetivo, biodiversidad y bioseguridad.' },
  { termino: 'Edición Génica (CRISPR)', definicion: 'Tecnología biotecnológica avanzada que permite realizar modificaciones específicas en la secuencia de ADN de un organismo utilizando herramientas moleculares diseñadas para reconocer y alterar regiones determinadas del genoma, sin necesidad de introducir necesariamente genes externos, representando una evolución respecto a la ingeniería genética tradicional que generalmente incorpora ADN foráneo. La tecnología CRISPR-Cas (Clustered Regularly Interspaced Short Palindromic Repeats) fue descubierta originalmente como un sistema de defensa natural de bacterias contra virus, donde las bacterias almacenan información de infecciones anteriores para reconocer y destruir material genético invasor. Los científicos adaptaron este sistema como herramienta de edición genética compuesta por: ARN guía (gRNA), una molécula diseñada para reconocer una secuencia específica de ADN funcionando como dirección molecular, y la enzima Cas9 que actúa como tijera molecular cortando el ADN en el sitio preciso para permitir modificaciones. El mecanismo de funcionamiento consiste en diseñar el ARN guía complementario al gen objetivo, que dirige la enzima Cas9 al sitio exacto del genoma donde realiza un corte específico, activando los mecanismos naturales de reparación celular que pueden generar diferentes tipos de modificación. Existen varios tipos de edición génica: knock out (eliminación de un gen específico desactivando características no deseadas o estudiando funciones genéticas), knock in (inserción o corrección de secuencias para corregir mutaciones o incorporar nuevas funciones), edición de bases (cambio de una letra del ADN sin cortar completamente la molécula, ofreciendo mayor precisión y menor daño genético) y edición prime o prime editing (tecnología avanzada que permite insertar, eliminar o reemplazar fragmentos pequeños de ADN con alta precisión, considerada una evolución de CRISPR). Las aplicaciones agrícolas incluyen: resistencia a enfermedades (modificación de genes de susceptibilidad a hongos, bacterias y virus vegetales), tolerancia a sequía (genes relacionados con cierre estomático, raíces profundas, eficiencia hídrica y respuesta hormonal), tolerancia a salinidad (genes de transporte iónico, eliminación de sodio y regulación osmótica), mejora del sistema radicular (mayor desarrollo, arquitectura eficiente y mejor asociación con micorrizas), eficiencia en uso de nutrientes (plantas que utilizan mejor nitrógeno, fósforo y potasio reduciendo dependencia de fertilizantes externos), mejora nutricional (aumento de vitaminas, minerales, proteínas y antioxidantes) y adaptación al cambio climático (temperaturas extremas, sequías prolongadas y cambios ambientales). En microorganismos agrícolas, la edición génica permite desarrollar bacterias con mayor capacidad para fijar nitrógeno, solubilizar fósforo y producir bioestimulantes, así como biopesticidas optimizados y consorcios microbianos diseñados con funciones complementarias. La edición génica se diferencia de la transgénesis en que no introduce ADN externo (generalmente), ofrece mayor precisión, modifica genes existentes en lugar de añadir nuevos, y requiere menor tiempo de desarrollo. Su potencial se multiplica al combinarse con inteligencia artificial para predicción de genes, genómica de plantas, biología sintética y agricultura personalizada adaptada a suelo, clima, microbioma y sistema productivo específico.' },
  // ─── Agricultura Biotecnológica ───
  { termino: 'Agricultura Biotecnológica', definicion: 'Modelo productivo que utiliza herramientas de la biología moderna para mejorar cultivos, microorganismos, procesos agrícolas y sistemas ecológicos mediante el conocimiento del ADN, microbiomas, metabolismo y relaciones biológicas, integrando genética, microbiología, bioquímica, ecología, ingeniería biológica y tecnologías digitales. Su principio fundamental es comprender y utilizar los procesos biológicos de la naturaleza para mejorar la producción agrícola, transitando desde una agricultura basada principalmente en insumos externos (fertilizantes minerales, pesticidas químicos) hacia una agricultura basada en organismos vivos, interacciones ecológicas, información genética e inteligencia biológica. Se sustenta en cuatro pilares: 1) Genética y genómica agrícola (secuenciación genética, marcadores moleculares, ingeniería genética y edición génica para desarrollar cultivos con resistencia a enfermedades, tolerancia a sequía, mayor eficiencia nutricional y mejor calidad alimentaria, identificando genes asociados a rendimiento, resistencia y adaptación climática); 2) Microbiología agrícola y microbioma (reconocimiento de que las plantas forman un holobionte planta-microorganismo donde bacterias, hongos, arqueas y microorganismos asociados participan en fijación de nitrógeno, movilización de fósforo, producción hormonal, defensa contra patógenos, formación de humus y almacenamiento de carbono; microorganismos clave incluyen PGPR como Bacillus, Pseudomonas, Azospirillum, hongos micorrícicos arbusculares para absorción mineral y comunicación vegetal, y Trichoderma para control biológico y estimulación vegetal); 3) Bioinsumos agrícolas (productos derivados de organismos vivos o sus metabolitos como alternativa biológica a insumos químicos: biofertilizantes con fijadores de nitrógeno y solubilizadores de fósforo, bioestimulantes con extractos biológicos, microorganismos, sustancias húmicas y aminoácidos que activan procesos fisiológicos y mejoran tolerancia al estrés, biopesticidas con Bacillus thuringiensis, Beauveria bassiana, Metarhizium y Trichoderma, y fermentaciones agrícolas para producción de microorganismos beneficiosos, metabolitos, enzimas y biofertilizantes líquidos); y 4) Tecnologías digitales y agricultura inteligente (inteligencia artificial para analizar datos genómicos, microbiomas, clima, suelo y rendimiento permitiendo predicción de enfermedades, selección genética y diseño de bioinsumos; agricultura de precisión con sensores, drones, imágenes satelitales y sistemas GPS para aplicar recursos exactamente donde son necesarios). La agricultura biotecnológica busca reconstruir el microbioma del suelo mediante inoculantes, consorcios microbianos, compost enriquecido y micorrizas, restaurando diversidad microbiana, redes tróficas y relaciones simbióticas. Contribuye a la mitigación del cambio climático mediante captura de carbono (aumento de materia orgánica, biochar, microorganismos estabilizadores), menor uso de fertilizantes sintéticos (fijación biológica de nitrógeno, mejor eficiencia nutricional) y resistencia climática (cultivos adaptados y microbiomas funcionales). Se integra con la agricultura regenerativa mediante mínima perturbación del suelo, cobertura permanente, diversidad vegetal, aumento de carbono orgánico y activación microbiológica, donde la biotecnología aporta herramientas y la ecología proporciona el marco de funcionamiento. La agricultura biotecnológica representa la transición desde una visión industrial de la agricultura hacia una visión basada en sistemas vivos, donde la combinación de genética, microbiología, bioinsumos y tecnologías digitales permitirá construir sistemas agrícolas capaces de producir alimentos mientras regeneran los ecosistemas.' },
  // ─── Fotosíntesis, Respiración y Transpiración ───
  { termino: 'Fotosíntesis', definicion: 'Proceso bioquímico fundamental mediante el cual los organismos fotosintéticos (plantas, algas, cianobacterias) capturan energía luminosa proveniente del Sol y la transforman en energía química almacenada en moléculas orgánicas, utilizando dióxido de carbono atmosférico y agua absorbida por las raíces, liberando oxígeno como producto secundario (ecuación general: 6CO₂ + 6H₂O + energía luminosa → C₆H₁₂O₆ + 6O₂). Constituye la base energética de prácticamente todos los ecosistemas terrestres y acuáticos, funcionando como el puente entre el mundo físico y el mundo biológico al convertir la energía solar en alimento que sostiene la vida. La fotosíntesis ocurre principalmente en las hojas, dentro de orgánulos celulares especializados llamados cloroplastos, que contienen clorofila (pigmento principal, con clorofila a que participa directamente en la conversión energética y clorofila b que amplía el rango de luz aprovechable), carotenoides (pigmentos amarillos y anaranjados que capturan luz adicional y protegen contra exceso de radiación), membranas tilacoidales (estructuras membranosas donde ocurre la captura de luz, conteniendo fotosistemas y cadenas transportadoras de electrones) y estroma (matriz interna donde ocurre la fijación del carbono mediante enzimas, ADN del cloroplasto y ribosomas). La fotosíntesis comprende dos grandes etapas: fase luminosa o dependiente de la luz (ocurre en las membranas de los tilacoides transformando energía luminosa en energía química mediante fotólisis del agua que separa H₂O en oxígeno liberado a la atmósfera, hidrógeno y electrones; cadena de transporte de electrones que genera un gradiente de protones; y producción de ATP y NADPH que serán utilizados en la siguiente etapa) y fase oscura o ciclo de Calvin (ocurre en el estroma utilizando los productos de la fase luminosa para transformar CO₂ atmosférico en moléculas orgánicas mediante la enzima RuBisCO - ribulosa-1,5-bisfosfato carboxilasa/oxigenasa, una de las proteínas más abundantes del planeta, que captura carbono atmosférico y lo convierte en glucosa, sacarosa y almidón para crecimiento, formación de frutos, producción de semillas y almacenamiento energético). La fotosíntesis está limitada por varios factores: intensidad luminosa (baja luz reduce producción energética; alta luz excesiva causa estrés oxidativo), disponibilidad de CO₂ (mayor disponibilidad aumenta fotosíntesis hasta cierto límite), disponibilidad de agua (indispensable para transporte, apertura estomática y fotosíntesis; su falta provoca cierre de estomas y menor entrada de CO₂), temperatura (las enzimas fotosintéticas tienen rangos óptimos; temperaturas extremas dañan proteínas y reducen metabolismo) y nutrientes minerales como nitrógeno (clorofila y enzimas), magnesio (elemento central de la molécula de clorofila), hierro (transporte electrónico) y fósforo (ATP y transferencia energética). Existen diferentes estrategias adaptativas: plantas C3 (trigo, arroz, soja, menor eficiencia bajo altas temperaturas y mayor sensibilidad a sequía), plantas C4 (maíz, sorgo, caña de azúcar, mayor eficiencia con alta radiación y mejor uso del agua) y plantas CAM (cactus, suculentas, apertura estomática nocturna y ahorro de agua adaptadas a ambientes secos). La fotosíntesis tiene profundas consecuencias en el suelo: los azúcares producidos son transportados hacia raíces, microorganismos y tejidos de reserva; una parte importante del carbono fijado se libera al suelo mediante exudados radiculares (azúcares, aminoácidos, ácidos orgánicos, metabolitos secundarios) que alimentan microorganismos beneficiosos, estableciendo que la fotosíntesis alimenta tanto a la planta como al microbioma del suelo. El rendimiento de un cultivo depende de la cantidad de luz capturada, la eficiencia fotosintética y la distribución del carbono. La fotosíntesis tiene un papel fundamental en el ciclo del carbono: las plantas capturan CO₂ atmosférico, transforman carbono en biomasa y lo almacenan en madera, raíces y materia orgánica del suelo, convirtiendo a los ecosistemas vegetales en importantes reguladores climáticos. Una parte del carbono capturado termina formando residuos vegetales, raíces muertas y compuestos orgánicos que alimentan procesos de humificación, formación de agregados y actividad microbiana, siendo la fotosíntesis el origen del carbono que construye la fertilidad del suelo.' },
  { termino: 'Respiración Vegetal', definicion: 'Conjunto de procesos bioquímicos mediante los cuales las células de las plantas degradan moléculas orgánicas, principalmente azúcares producidos por la fotosíntesis, para liberar energía utilizable en forma de ATP (adenosín trifosfato), que funciona como moneda energética permitiendo procesos esenciales como crecimiento celular, división celular, absorción de nutrientes, transporte interno, formación de raíces, síntesis de proteínas, defensa contra patógenos y reproducción (ecuación general: C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ATP). Mientras la fotosíntesis almacena energía, la respiración la libera para las actividades celulares, formando un ciclo complementario donde la fotosíntesis produce combustible y la respiración lo convierte en energía utilizable. La respiración ocurre durante todo el ciclo de vida de la planta y es necesaria para germinación de semillas, crecimiento de raíces, formación de hojas, floración, desarrollo de frutos, maduración y respuesta al estrés, ocurriendo principalmente en las mitocondrias (orgánulos celulares conocidos como centrales energéticas de la célula, compuestos por membrana externa protectora, membrana interna con proteínas transportadoras y complejos respiratorios, y matriz mitocondrial donde ocurren procesos metabólicos como el ciclo de Krebs). La respiración celular comprende cinco etapas coordinadas: glucólisis (ocurre en el citoplasma celular, consiste en la ruptura de glucosa en moléculas más pequeñas llamadas piruvato, produciendo ATP inicial, NADH y compuestos intermediarios sin requerir oxígeno directamente), oxidación del piruvato (el piruvato entra en la mitocondria transformándose en Acetil-CoA que ingresará al ciclo de Krebs), ciclo de Krebs o ciclo del ácido cítrico (ocurre en la matriz mitocondrial extrayendo electrones ricos en energía de moléculas orgánicas, produciendo CO₂, NADH, FADH₂ y ATP), cadena de transporte de electrones (etapa donde se produce la mayor cantidad de ATP: los electrones pasan por complejos proteicos en la membrana interna mitocondrial generando un gradiente de protones que proporciona energía para sintetizar ATP) y fosforilación oxidativa (producción final de ATP mediante la enzima ATP sintasa, que funciona como una máquina molecular utilizando el movimiento de protones para fabricar energía; una molécula de glucosa puede producir aproximadamente 30 a 32 moléculas de ATP dependiendo de las condiciones celulares). Existe respiración aeróbica (utiliza oxígeno, es la forma más eficiente de obtener energía) y respiración anaeróbica o fermentación (ocurre cuando hay poco oxígeno, por ejemplo en tejidos sumergidos o raíces en suelos inundados, pudiendo producir alcohol, ácido láctico y menor cantidad de ATP). Las raíces tienen una alta demanda energética necesitando ATP para absorber minerales, transportar iones, crecer y formar pelos radicales; por eso un suelo sin oxígeno afecta gravemente la función radicular. La respiración vegetal depende directamente de la salud del suelo: un suelo equilibrado proporciona oxígeno, agua disponible, minerales y microorganismos beneficiosos que influyen mediante micorrizas (mejoran absorción mineral y eficiencia energética), bacterias PGPR (estimulan crecimiento radicular y metabolismo vegetal) y descomponedores (liberan nutrientes necesarios para mantener la actividad celular). La actividad respiratoria depende de la temperatura (temperatura baja reduce metabolismo, temperatura óptima aumenta actividad enzimática, temperatura excesiva causa estrés metabólico), disponibilidad de oxígeno (niveles bajos disminuyen producción de ATP y aumentan fermentación), disponibilidad de azúcares (más carbohidratos disponibles aumentan capacidad energética) y nutrición mineral con fósforo (necesario para formar ATP), nitrógeno (enzimas y proteínas) y magnesio (procesos metabólicos). Los frutos continúan respirando después de la cosecha, proceso que determina maduración, conservación y calidad (algunos frutos presentan comportamiento climatérico con aumento de respiración durante la maduración, como tomate, manzana y plátano). La agricultura moderna debe comprender que aumentar la productividad no depende solamente de producir más azúcar mediante fotosíntesis, sino de permitir que la planta pueda utilizar eficientemente esa energía a través de una respiración saludable, donde un suelo vivo con buena aireación y microbiología activa es fundamental para mantener una respiración radicular equilibrada.' },
  { termino: 'Transpiración Vegetal', definicion: 'Proceso fisiológico fundamental mediante el cual las plantas pierden agua en forma de vapor desde los tejidos vegetales hacia la atmósfera, principalmente a través de los estomas ubicados en las hojas, generando una corriente continua de agua que conecta el suelo, la raíz, el xilema, la hoja y la atmósfera, y que constituye la fuerza invisible que permite transportar minerales desde el suelo, mantener la actividad fotosintética, regular la temperatura de la planta y mantener la presión interna celular o turgencia. El agua representa entre un 70 y 95 % del peso fresco de muchas plantas y participa en prácticamente todos los procesos fisiológicos. El sistema hidráulico vegetal está formado por raíces (donde el agua ingresa mediante pelos radicales que aumentan la superficie de absorción, mediante ósmosis desde zonas con mayor potencial hídrico hacia menor potencial hídrico; los hongos micorrícicos aumentan la capacidad de absorción funcionando como extensión del sistema radicular con mayor exploración del suelo, mejor captación de agua y mayor resistencia a sequía), xilema (tejido encargado de transportar agua y minerales desde la raíz hasta las hojas mediante el mecanismo de cohesión entre moléculas de agua que forman una columna continua, adhesión a las paredes internas del xilema que ayuda al ascenso, y tensión transpiratoria generada por la evaporación desde las hojas que produce una fuerza de succión que impulsa el movimiento del agua), estomas (pequeñas aberturas ubicadas principalmente en las hojas que controlan la entrada de CO₂, la salida de oxígeno y la pérdida de agua, formados por un poro estomático y células guardianas que regulan su apertura y cierre: estoma abierto permite entrada de CO₂, fotosíntesis y transpiración; estoma cerrado reduce pérdida de agua pero también limita fotosíntesis). La apertura estomática está regulada por múltiples factores: luz (generalmente favorece apertura), disponibilidad de agua (en sequía la planta produce ácido abscísico ABA que induce cierre estomático), concentración de CO₂ (altos niveles internos reducen apertura), temperatura (elevada aumenta demanda de agua) y humedad atmosférica (aire seco aumenta pérdida de agua; aire húmedo reduce transpiración). Existen tres tipos de transpiración: estomática (principal vía mediante estomas), cuticular (a través de la cutícula de la hoja, menor pero importante en algunas especies) y lenticelar (ocurre en tallos leñosos mediante lenticelas). La transpiración cumple cuatro funciones fisiológicas esenciales: transporte de nutrientes (los minerales absorbidos por las raíces viajan disueltos en agua: nitrógeno, fósforo, potasio, calcio, magnesio, micronutrientes; sin transpiración el transporte mineral disminuye significativamente; calcio tiene baja movilidad dentro de la planta y depende mucho del flujo de agua, por eso las deficiencias aparecen en hojas jóvenes y frutos; boro está relacionado con crecimiento celular y tejidos jóvenes), regulación de temperatura (la evaporación del agua desde las hojas consume energía térmica permitiendo enfriar la superficie foliar, evitar daños por altas temperaturas y mantener actividad enzimática, funcionando como sistema natural de refrigeración), mantenimiento de la fotosíntesis (cuando los estomas están abiertos entra CO₂ que permite la producción de azúcares) y mantenimiento de la turgencia celular (el agua mantiene la presión interna de las células vegetales permitiendo hojas firmes, crecimiento celular y expansión de tejidos). Las plantas buscan equilibrar la captura de carbono con la pérdida de agua mediante la eficiencia en el uso del agua (EUA), donde una planta eficiente produce más biomasa con menor consumo hídrico. Las plantas desarrollan estrategias adaptativas a la sequía: raíces profundas para mayor acceso al agua, cutículas gruesas que reducen pérdidas, estomas regulados que controlan evaporación y metabolismo CAM que permite ahorrar agua mediante apertura nocturna de estomas. El manejo agrícola debe favorecer una adecuada regulación hídrica mediante un suelo sano con buena estructura, materia orgánica, alta capacidad de retención hídrica y porosidad equilibrada que permita agua disponible, oxígeno radicular y mayor transpiración eficiente. La materia orgánica aumenta la retención hídrica, mejora la estructura y favorece raíces, funcionando como reserva natural de agua. Los microorganismos ayudan mediante mayor desarrollo radicular, producción hormonal y mejora de absorción (micorrizas, Bacillus, Azospirillum). Frente al cambio climático con aumento de temperaturas, sequías y olas de calor que modifican la dinámica hídrica vegetal, la agricultura futura requiere variedades eficientes en agua, manejo biológico del suelo, sistemas agroforestales y cobertura permanente para mantener una transpiración equilibrada que conecte el suelo, la planta y la atmósfera.' },
  // ─── Hormonas y Desarrollo ───
  { termino: 'Hormonas Vegetales (Fitohormonas)', definicion: 'Moléculas orgánicas señalizadoras producidas naturalmente por la planta en concentraciones muy bajas que regulan procesos fisiológicos específicos como crecimiento, desarrollo, reproducción y respuesta ambiental mediante cambios en la expresión genética, metabolismo y comportamiento celular, funcionando como un sistema de comunicación química interna equivalente al sistema nervioso de los animales. A diferencia de las hormonas animales, no son producidas por glándulas especializadas, pueden sintetizarse en múltiples tejidos, transportarse a corta o larga distancia y sus efectos dependen del estado fisiológico de la planta y de la presencia de otras señales. Las ocho grandes familias de fitohormonas son: auxinas (ácido indol-3-acético AIA producido en ápices de crecimiento, hojas jóvenes y semillas, con transporte polar desde brotes hacia raíces, que regulan elongación celular mediante activación de bombas de protones y proteínas expansinas que acidifican y flexibilizan la pared celular, formación de raíces laterales y adventicias, dominancia apical donde la punta del tallo inhibe yemas laterales, y desarrollo de frutos), giberelinas (ácido giberélico GA3 que regula crecimiento del tallo mediante división y elongación celular, germinación de semillas activando α-amilasas que degradan almidón en azúcares para alimentar al embrión, expansión celular y desarrollo del fruto incluyendo crecimiento sin semillas), citoquininas (producidas principalmente en raíces jóvenes, semillas y frutos en desarrollo, regulan división celular, formación de brotes, retraso de senescencia manteniendo hojas activas mediante prevención de degradación de clorofila y pérdida de proteínas, y establecen un equilibrio auxina/citoquinina que determina el tipo de crecimiento: mayor auxina favorece raíces, mayor citoquinina favorece brotes, principio fundamental en cultivo de tejidos y propagación vegetal), ácido abscísico ABA (hormona de supervivencia vegetal cuya función principal es permitir que la planta enfrente estrés hídrico: cuando la raíz detecta déficit hídrico aumenta ABA que viaja hacia las hojas induciendo cierre estomático para reducir pérdida de agua, participando también en dormancia de semillas, adaptación al frío y acumulación de reservas), etileno (hormona gaseosa única que puede difundirse fácilmente y actuar a distancia, regula maduración de frutos mediante cambio de color, ablandamiento, aromas y transformación de almidones en azúcares, senescencia con caída de hojas y envejecimiento floral, y respuesta a estrés mecánico como inundación, golpes y ataques de insectos), brasinoesteroides (familia descubierta recientemente que participa en crecimiento celular, desarrollo vascular, tolerancia al estrés, fotosíntesis, resistencia al frío y recuperación después de daños), ácido salicílico (hormona fundamental en defensa contra microorganismos que activa la resistencia sistémica adquirida SAR generando memoria defensiva contra bacterias, hongos y virus) y jasmonatos (regulan respuestas frente a insectos herbívoros, heridas y estrés ambiental mediante activación de compuestos tóxicos, proteínas defensivas y metabolitos secundarios). Las fitohormonas no trabajan de forma aislada sino mediante redes de señalización: auxina + citoquinina controlan raíz, brotes y arquitectura vegetal; ABA + etileno regulan estrés hídrico y envejecimiento; ácido salicílico + jasmonatos determinan estrategias defensivas diferenciadas (salicílico contra patógenos biotróficos, jasmonatos contra insectos y daños físicos). Los microorganismos del suelo también producen moléculas similares a hormonas: bacterias PGPR producen auxinas, citoquininas y ABA; hongos micorrícicos modifican señales hormonales, arquitectura radicular y tolerancia al estrés, formando una red integrada planta-microorganismo donde las hormonas representan el lenguaje interno que conecta genética, ambiente, microbiología, nutrición y productividad agrícola.' },
  { termino: 'Desarrollo Radicular', definicion: 'Proceso mediante el cual la planta construye la arquitectura subterránea formada por raíz principal, raíces laterales, raíces adventicias y pelos radicales, constituyendo un sistema altamente especializado que funciona como órgano de exploración del suelo, centro de comunicación con microorganismos, regulador hormonal, almacén de reservas y sensor ambiental determinante para la nutrición, resistencia y productividad agrícola. La raíz está organizada anatómicamente en varias regiones especializadas: cofia o caliptra (estructura protectora en la punta que protege el meristema radical, facilita la penetración en el suelo, percibe la gravedad y produce mucílagos que lubrican el avance y favorecen la interacción microbiana), zona meristemática o meristema apical radical (región de división celular con células madre que originan tejidos conductores, epidermis, corteza y tejidos internos), zona de elongación (las células recién formadas aumentan rápidamente de tamaño permitiendo crecimiento longitudinal, exploración del suelo y penetración entre partículas, regulado principalmente por auxinas) y zona de diferenciación (las células adquieren funciones específicas formando pelos radicales, vasos conductores y tejidos especializados). Los pelos radicales son extensiones microscópicas de células epidérmicas que aumentan enormemente la superficie de contacto con el suelo para capturar agua, absorber minerales, explorar microporos e interactuar con bacterias beneficiosas, pudiendo una planta producir millones durante su desarrollo. La arquitectura radicular incluye profundidad, distribución lateral, número de raíces secundarias, longitud total y densidad de pelos radicales, con dos tipos principales: sistema pivotante (raíz principal profunda con raíces laterales secundarias, característico de dicotiledóneas como alfalfa, tomate y frutales, que permite acceso a agua profunda y mayor resistencia a sequía) y sistema fasciculado (muchas raíces similares con alta exploración superficial, característico de gramíneas como maíz, trigo y arroz, que permite captura rápida de nutrientes superficiales y alta eficiencia en absorción). El desarrollo radicular está regulado por una compleja interacción hormonal donde las auxinas estimulan formación de raíces laterales, adventicias y orientación radicular; las citoquininas regulan división celular y equilibrio entre crecimiento aéreo y radical; el ácido abscísico permite adaptación a sequía; y el etileno participa en respuesta a compactación, inundación y formación de raíces adventicias. La raíz funciona como órgano sensor detectando continuamente humedad, temperatura, oxígeno, minerales y presencia microbiana, modificando su arquitectura según las condiciones: falta de fósforo aumenta pelos radicales y raíces laterales superficiales; falta de nitrógeno aumenta exploración del suelo. Las raíces liberan exudados radiculares (azúcares, aminoácidos, ácidos orgánicos, flavonoides, enzimas, compuestos fenólicos) hacia la rizósfera, que alimentan microorganismos, movilizan minerales como fósforo, hierro y micronutrientes, y permiten comunicarse atrayendo microorganismos beneficiosos y estableciendo simbiosis. La zona influenciada por la raíz o rizósfera puede contener actividad biológica cientos de veces mayor que el suelo alejado, formando el microbioma radicular con bacterias PGPR que producen auxinas, sideróforos y compuestos antimicrobianos para mayor crecimiento radical y mejor nutrición, y hongos micorrícicos que proporcionan fósforo, micronutrientes y agua a cambio de carbono y azúcares. La absorción mineral ocurre mediante transporte activo (utiliza energía metabólica para incorporar nitratos, fosfatos, potasio, calcio y micronutrientes) y transporte pasivo (depende de gradientes de concentración y movimiento del agua). Las prácticas agrícolas modifican profundamente el sistema radicular: labranza intensiva puede romper raíces y reducir estructura y microbioma; el suelo vivo favorece agregados estables, micorrizas, raíces profundas y mayor carbono orgánico; las coberturas vegetales estimulan actividad biológica, protección térmica e infiltración; y el compost y biofertilizantes aumentan disponibilidad nutricional, diversidad microbiana y desarrollo radical.' },
  { termino: 'Floración', definicion: 'Evento fisiológico fundamental en el ciclo de vida vegetal donde la planta modifica su programa de crecimiento vegetativo (producción de hojas, tallos, raíces y reservas energéticas) y activa la fase reproductiva formando flores, órganos reproductivos, semillas y frutos, resultado de una compleja integración entre genética, hormonas, edad de la planta, temperatura, luz, disponibilidad de nutrientes, estado hídrico e interacción con microorganismos. La transición floral ocurre cuando el meristema apical del tallo SAM (tejido formado por células capaces de dividirse continuamente que durante la fase vegetativa produce hojas) se transforma en meristema reproductivo capaz de producir sépalos, pétalos, estambres y carpelos, implicando una reorganización completa del programa genético de la planta. Las principales señales que inducen la floración incluyen: fotoperiodo (relación entre horas de luz y oscuridad durante un ciclo diario, determinando plantas de día largo como trigo, espinaca y lechuga que florecen cuando los días son largos, plantas de día corto como arroz, soja y crisantemo que florecen cuando la noche supera cierto tiempo crítico, y plantas neutras como tomate y pepino que no dependen fuertemente del fotoperiodo), temperatura (mediante vernalización, proceso donde algunas plantas necesitan pasar por un período de bajas temperaturas para activar la floración, como trigo de invierno y cebada, mediante cambios epigenéticos que activan genes florales), edad de la planta (madurez necesaria para ser competente a la floración), hormonas (giberelinas fundamentales para activación floral y elongación del tallo floral; auxinas participan en desarrollo floral y formación de frutos; citoquininas favorecen actividad del meristema), disponibilidad energética (relación carbono disponible / demanda metabólica determina si la planta puede invertir recursos en flores) y estrés ambiental (sequía puede retrasar floración o abortar flores; temperaturas extremas afectan formación del polen y viabilidad floral). La percepción de la luz ocurre mediante fotorreceptores: fitocromos que detectan luz roja y roja lejana participando en germinación, crecimiento y floración, y criptocromos que detectan luz azul regulando el reloj biológico y desarrollo floral. Uno de los descubrimientos más importantes fue el florígeno, señal producida principalmente en las hojas que viaja por el floema hacia el meristema para activar la transición floral, siendo la proteína FT (FLOWERING LOCUS T) la más estudiada. La floración depende de una red de genes reguladores, siendo el modelo clásico el modelo ABC de desarrollo floral donde los genes A determinan sépalos y pétalos, los genes B determinan pétalos y estambres, y los genes C determinan estambres y carpelos, cuya combinación define la arquitectura floral. El equilibrio nutricional es esencial: exceso de nitrógeno favorece crecimiento vegetativo retrasando floración; fósforo es importante para energía metabólica, formación de flores y desarrollo reproductivo; potasio participa en transporte de azúcares, calidad floral y resistencia al estrés; boro es fundamental para formación del tubo polínico y fecundación. El microbioma del suelo influye indirectamente en la reproducción vegetal: micorrizas favorecen absorción de fósforo, equilibrio hídrico y estabilidad fisiológica; PGPR producen auxinas, citoquininas y compuestos protectores resultando en plantas mejor preparadas para florecer. La floración es fundamental no solo para la producción agrícola sino para la reproducción vegetal, biodiversidad, alimentación de polinizadores y continuidad de ecosistemas, representando un punto de conexión entre plantas, insectos, microorganismos y ambiente.' },
  { termino: 'Fructificación', definicion: 'Proceso fisiológico mediante el cual el ovario floral se desarrolla después de la polinización y fecundación hasta convertirse en un fruto maduro destinado a proteger las semillas, facilitar la dispersión genética, almacenar reservas y producir alimentos, determinando el rendimiento agrícola, tamaño del fruto, calidad comercial, sabor, contenido nutricional y vida poscosecha. El fruto está compuesto principalmente por el pericarpio (pared del fruto derivada del ovario) que se divide en epicarpio (parte externa como piel de manzana), mesocarpio (zona media carnosa como pulpa del durazno) y endocarpio (capa interna cercana a la semilla como carozo del durazno). El proceso inicia con la polinización (traslado del polen desde la antera hasta el estigma de la flor mediante viento, insectos, aves o intervención humana; la mayoría de cultivos dependen de polinizadores como abejas, abejorros y mariposas que favorecen mayor número de frutos, más uniformes y mejor calidad comercial) seguida de la fecundación (germinación del grano de polen que produce un tubo polínico que crece hasta llegar al óvulo donde ocurre la fecundación, resultando en semilla en desarrollo que activa el crecimiento del fruto). El cuajado del fruto (momento donde la flor mantiene su desarrollo y comienza a formar fruto) está controlado por hormonas: auxinas producidas por semillas jóvenes estimulan crecimiento del ovario, división celular y formación inicial del fruto; giberelinas promueven expansión del fruto, aumento de tamaño y crecimiento celular; citoquininas estimulan multiplicación celular y formación inicial del tejido del fruto. Algunas plantas pueden desarrollar frutos partenocárpicos (sin semillas) sin fecundación, naturalmente o mediante tratamientos hormonales, como algunas variedades de tomate, banana y cítricos. El desarrollo del fruto ocurre en tres fases: Fase I de división celular (inmediatamente después de la fecundación, aumento del número de células y formación de tejidos básicos que determina el potencial del tamaño final), Fase II de expansión celular (las células aumentan volumen, contenido de agua y reservas, dependiendo de disponibilidad hídrica, potasio, calcio y carbono fotosintético), y Fase III de maduración (cambios de color por degradación de clorofila y producción de carotenoides y antocianinas, ablandamiento por degradación de pectinas y componentes de pared celular, producción de aromas mediante compuestos volátiles, acumulación de azúcares donde el almidón se transforma en glucosa, fructosa y sacarosa). Los frutos se clasifican en climatéricos (continúan madurando después de cosechados con aumento de respiración y etileno, como tomate, manzana y plátano) y no climatéricos (deben cosecharse cerca de su madurez, como uva, cítricos y fresa). Los frutos funcionan como sumideros de carbono donde la planta produce azúcares mediante fotosíntesis que viajan por el floema hacia frutos y semillas; una alta capacidad fotosintética permite mayor tamaño, más sólidos solubles y mejor calidad. El agua es esencial para división celular, transporte de nutrientes y expansión del fruto; déficit hídrico causa caída de frutos, frutos pequeños y baja calidad; exceso puede provocar menor concentración de azúcares y problemas sanitarios. La nutrición mineral durante la fructificación cumple funciones específicas: nitrógeno para proteínas y crecimiento aunque su exceso produce mucho follaje y menor calidad; fósforo para energía celular y desarrollo reproductivo; potasio como elemento clave en transporte de azúcares, tamaño, coloración y sabor; calcio fundamental para estructura celular y firmeza del fruto cuya deficiencia causa pudrición apical en tomate; boro para germinación del polen, formación de semillas y transporte de azúcares. El microbioma del suelo influye indirectamente en la producción de frutos: micorrizas favorecen absorción de fósforo, nutrición hídrica y estabilidad fisiológica; bacterias PGPR producen auxinas, sideróforos y sustancias protectoras resultando en plantas con mayor capacidad productiva. La fructificación representa la culminación visible de todos los procesos fisiológicos de la planta, resultado de la coordinación entre genética, ambiente, hormonas, microorganismos y manejo agrícola.' },
  // ─── Estrés Abiótico ───
  { termino: 'Estrés Abiótico', definicion: 'Estado fisiológico producido por factores ambientales de origen no biológico (sequía, altas temperaturas, bajas temperaturas, salinidad, inundación, deficiencias minerales, toxicidad por elementos, radiación excesiva) que superan la capacidad normal de adaptación de la planta, limitando su crecimiento, desarrollo o reproducción, y que afecta principalmente fotosíntesis, respiración, absorción de nutrientes, crecimiento radicular y rendimiento agrícola. La planta detecta estos cambios mediante sistemas especializados que transmiten señales mediante calcio celular, especies reactivas de oxígeno, hormonas y proteínas reguladoras, activando una secuencia de percepción, señalización y adaptación donde modifica metabolismo, crecimiento y estructura. En el estrés hídrico por sequía, el agua es indispensable para fotosíntesis, transporte mineral, expansión celular y regulación térmica; cuando disminuye el agua disponible, la raíz detecta el menor potencial hídrico y aumenta ácido abscísico ABA que viaja hacia las hojas provocando cierre estomático (reduce pérdida de agua pero también entrada de CO₂ y fotosíntesis), la planta puede desarrollar raíces más profundas, mayor crecimiento lateral y más pelos radicales con mayor asociación micorrícica, y las células acumulan osmoprotectores como prolina, azúcares solubles, aminoácidos y betaína que ayudan a conservar volumen celular, proteínas funcionales y membranas. En el estrés térmico por altas temperaturas, el calor excesivo provoca cierre estomático, reducción fotosintética, daño en cloroplastos, pérdida de polen viable y aborto floral, activando la producción de proteínas de choque térmico HSP que actúan como chaperonas moleculares protegiendo proteínas, evitando desnaturalización y recuperando estructuras dañadas, mientras la planta modifica orientación de hojas, grosor de cutícula y producción de ceras. En el estrés por bajas temperaturas, el frío afecta membranas celulares, metabolismo enzimático y transporte de nutrientes; cuando el agua celular se congela forma cristales de hielo que pueden romper membranas y estructuras celulares, activando la producción de azúcares protectores, proteínas anticongelantes y lípidos de membrana; algunas especies requieren frío mediante vernalización como señal ambiental para activar posteriormente la floración. En el estrés por salinidad, el exceso de sales produce estrés osmótico (dificultad para absorber agua aunque exista humedad) y toxicidad iónica por exceso de sodio Na⁺ y cloro Cl⁻ que daña enzimas, membranas y fotosistemas; las plantas tolerantes pueden excluir sales evitando que entren a la raíz, almacenarlas en vacuolas celulares o producir osmoprotectores. En el estrés por inundación, el exceso de agua reduce el oxígeno disponible en el suelo generando hipoxia (bajo nivel de oxígeno) o anoxia (ausencia casi total), afectando la respiración radicular, producción de ATP y absorción activa de nutrientes; algunas plantas producen raíces adventicias y aerénquima que permite transportar oxígeno hacia la raíz. El estrés nutricional por deficiencias incluye: nitrógeno (hojas amarillas, bajo crecimiento, menor proteína), fósforo (raíces poco desarrolladas, menor energía metabólica), potasio (reducida regulación hídrica y resistencia al estrés) y micronutrientes (enzimas, fotosíntesis y defensa afectados). Muchos tipos de estrés generan especies reactivas de oxígeno ROS (radical superóxido, peróxido de hidrógeno) que en exceso dañan ADN, proteínas, membranas y cloroplastos, siendo contrarrestadas por el sistema antioxidante vegetal enzimático (superóxido dismutasa, catalasa, peroxidasas) y no enzimático (vitamina C, vitamina E, glutatión, carotenoides). Las hormonas involucradas incluyen ABA (principal hormona de sequía, cierre estomático y supervivencia), etileno (envejecimiento, respuesta a inundación y heridas), jasmonatos (defensa y reparación celular) y ácido salicílico (resistencia y comunicación defensiva). Las plantas pueden desarrollar memoria de estrés mediante modificaciones epigenéticas que les permiten responder más rápidamente después de una exposición previa. La resistencia comienza en el suelo: un suelo vivo con mejor estructura, mayor retención de agua, disponibilidad mineral y microorganismos protectores favorece la tolerancia; micorrizas aumentan exploración del suelo, absorción de agua y fósforo, y resistencia a sequía; bacterias PGPR producen hormonas y mejoran crecimiento radical reduciendo el estrés vegetal.' },
  // ─── Estrés Biótico ───
  { termino: 'Estrés Biótico', definicion: 'Daño causado por organismos vivos (hongos fitopatógenos, bacterias patógenas, virus vegetales, insectos herbívoros, nematodos fitoparásitos, plantas competidoras) que afectan el crecimiento, desarrollo o productividad de una planta, activando un sofisticado sistema de defensa vegetal o inmunidad vegetal basado en reconocimiento molecular, señales químicas, barreras físicas, compuestos antimicrobianos, memoria inmunológica y cooperación con microorganismos beneficiosos. La primera línea de defensa incluye barreras físicas: cutícula vegetal (capa cerosa externa de hojas y frutos que dificulta entrada de patógenos), pared celular (formada por celulosa, hemicelulosa, lignina y pectinas que funciona como defensa mecánica) y tricomas (estructuras en hojas y tallos que actúan como barrera física y defensa contra insectos). El reconocimiento del enemigo ocurre mediante receptores especializados que detectan patrones moleculares asociados a microorganismos PAMP o MAMP (fragmentos de pared bacteriana, componentes de hongos), activando la inmunidad activada por patrones PTI. La defensa vegetal progresa en etapas: detección del invasor, señalización defensiva con calcio, especies reactivas de oxígeno y hormonas, activación genética de genes de defensa, y respuesta protectora produciendo proteínas defensivas, metabolitos secundarios y barreras químicas. La respuesta hipersensible HR consiste en muerte programada de células infectadas para aislar al patógeno, sacrificando una pequeña zona para proteger el tejido sano. La resistencia sistémica adquirida SAR permite que después de un ataque localizado la planta active defensas en otras partes mediante ácido salicílico, funcionando como memoria inmunológica vegetal que prepara tejidos distantes frente a futuros ataques. La resistencia sistémica inducida ISR es estimulada por microorganismos beneficiosos como bacterias PGPR, hongos beneficiosos y micorrizas, preparando a la planta para responder más rápidamente. Las hormonas de defensa incluyen tres grandes rutas: ácido salicílico SA (defensa contra bacterias, hongos biotróficos y virus activando proteínas PR y resistencia sistémica), jasmonatos JA (respuesta a herbívoros, daños mecánicos y hongos necrotróficos activando compuestos tóxicos e inhibidores digestivos) y etileno ET (respuesta a heridas, interacción con jasmonatos, maduración y senescencia). Las plantas producen miles de metabolitos secundarios defensivos: fenoles con función antimicrobiana y antioxidante (flavonoides, taninos), alcaloides tóxicos para herbívoros (nicotina, cafeína), terpenos para defensa química y comunicación con insectos, y fitoalexinas como antibióticos naturales producidos después de una infección. Las plantas pueden comunicarse entre sí mediante compuestos volátiles y señales hormonales que alertan plantas vecinas, atraen insectos benéficos y activan defensas. La planta moderna se entiende como un holobionte vegetal (planta + bacterias + hongos + microorganismos asociados) donde el microbioma ayuda mediante competencia contra patógenos, producción de antimicrobianos y estimulación inmunológica. Hongos beneficiosos como Trichoderma compiten con hongos patógenos, producen enzimas antifúngicas y estimulan defensas; las micorrizas favorecen mejor nutrición y mayor tolerancia. Bacterias PGPR protegen mediante competencia ocupando espacios donde podrían establecerse patógenos, antibiosis produciendo sustancias inhibitorias e inducción de resistencia preparando la planta para responder. El estrés biótico también incluye competencia entre plantas por luz, agua, nutrientes y espacio, incluyendo alelopatía donde algunas plantas liberan sustancias químicas que inhiben germinación y crecimiento de otras especies. La agricultura moderna busca fortalecer la resistencia natural mediante suelo vivo con microbioma diverso, diversidad vegetal con rotaciones y policultivos, bioinsumos como Trichoderma, Bacillus y micorrizas, y nutrición equilibrada que produce paredes celulares fuertes y mayor capacidad defensiva. El estrés abiótico y biótico están conectados: una planta debilitada por sequía presenta mayor susceptibilidad a enfermedades, por lo que la resistencia depende de la integración de ambiente, nutrición, microbioma y genética.' },
  // ─── Holobionte Vegetal ───
  { termino: 'Holobionte Vegetal', definicion: 'Unidad funcional formada por la planta (hospedador) y la comunidad de microorganismos asociados (bacterias, hongos, arqueas, virus) que habitan la superficie de sus tejidos, el interior de sus células, la zona alrededor de sus raíces y el suelo circundante, representando un cambio de paradigma donde la planta no se estudia como organismo individual sino como un sistema integrado donde la genética vegetal, el microbioma, el suelo y el ambiente funcionan como una unidad. El microbioma vegetal se divide en microbioma de la rizósfera (comunidad alrededor de la raíz con bacterias, hongos, protozoos y nematodos beneficiosos que participan en movilización de nutrientes, protección contra patógenos, producción hormonal y formación de estructura del suelo), microbioma endofítico (microorganismos que viven dentro de tejidos vegetales sin causar enfermedad, presentes en raíces, tallos, hojas y semillas, proporcionando protección interna, producción de metabolitos y tolerancia al estrés), y microbioma de la superficie vegetal o filósfera (microorganismos presentes en hojas, flores y frutos). La raíz es el principal punto de interacción entre planta, microorganismos y suelo, donde mediante exudados radicales (azúcares, aminoácidos, ácidos orgánicos, flavonoides) la planta libera señales químicas de comunicación. La rizósfera funciona como laboratorio biológico donde la planta modifica el ambiente alrededor de la raíz mediante liberación de carbono, modificación del pH y producción de señales químicas, y los microorganismos responden colonizando la zona y formando comunidades especializadas. Las micorrizas representan una de las asociaciones más importantes: el hongo micorrícico proporciona fósforo, nitrógeno, micronutrientes, agua y protección a la planta, mientras la planta proporciona carbohidratos, energía y compuestos orgánicos; los hongos pueden conectar diferentes plantas mediante redes micorrícicas comunes que permiten intercambio de nutrientes, comunicación química y transferencia de señales de defensa. Las bacterias promotoras del crecimiento vegetal PGPR producen auxinas, citoquininas, sideróforos, enzimas y compuestos antimicrobianos, mejorando nutrición (fijación de nitrógeno, solubilización de fósforo, movilización de minerales), estimulando el crecimiento mediante moléculas similares a hormonas, y protegiendo al competir con patógenos y activar defensas. La nutrición moderna reconoce que muchos nutrientes dependen de procesos biológicos: microorganismos especializados transforman nitrógeno atmosférico N₂ en formas utilizables, bacterias y hongos liberan fosfatos disponibles, y bacterias producen sideróforos que capturan hierro mejorando su disponibilidad. El microbioma funciona como primera línea defensiva: microorganismos beneficiosos ocupan nichos antes que los patógenos, producen sustancias antimicrobianas y activan resistencia inducida ISR. La tolerancia vegetal a estrés ambiental (sequía, salinidad, temperaturas extremas, contaminación) depende también de microorganismos asociados mediante mejor desarrollo radical, producción hormonal, regulación antioxidante y mejora nutricional. Cada órgano vegetal puede tener su propio microbioma especializado: raíz con bacterias y micorrizas, hoja con microorganismos de filósfera, semilla con microorganismos heredados, fruto con comunidades protectoras. Plantas y microorganismos han coevolucionado durante millones de años produciendo cooperación, especialización e intercambio de señales. Los ecosistemas naturales como bosques muestran cómo funciona un suelo vivo: redes formadas por árboles, raíces, hongos, bacterias y materia orgánica con alta biodiversidad, reciclaje permanente, mínima pérdida de nutrientes y estabilidad ecológica. El concepto de holobionte permite desarrollar biofertilizantes, bioestimulantes y manejo del suelo vivo basado en compost, cobertura vegetal, reducción de disturbios y diversidad biológica, avanzando desde la agricultura convencional de alimentar plantas hacia cultivar ecosistemas productivos donde la planta sea más resistente, el suelo más fértil y los microorganismos trabajen a favor del cultivo.' }
];
